    String benchmark;
    String ansi;
    String browserify;
    String eslint;
    String eslintPluginNodeca;
    String uglifyJs;
    String istanbul;
    String ndoc;
    String lodash;
    String devDependenciesAsync;
    String grunt;
    String gruntCli;
    String gruntSaucelabs;
    String gruntContribConnect;

    DevDependencies({
        required this.mocha,
        required this.benchmark,
        required this.ansi,
        required this.browserify,
        required this.eslint,
        required this.eslintPluginNodeca,
        required this.uglifyJs,
        required this.istanbul,
        required this.ndoc,
        required this.lodash,
        required this.devDependenciesAsync,
        required this.grunt,
        required this.gruntCli,
        required this.gruntSaucelabs,
        required this.gruntContribConnect,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        mocha: json["mocha"],
        benchmark: json["benchmark"],
        ansi: json["ansi"],
        browserify: json["browserify"],
        eslint: json["eslint"],
        eslintPluginNodeca: json["eslint-plugin-nodeca"],
        uglifyJs: json["uglify-js"],
        istanbul: json["istanbul"],
        ndoc: json["ndoc"],
        lodash: json["lodash"],
        devDependenciesAsync: json["async"],
        grunt: json["grunt"],
        gruntCli: json["grunt-cli"],
        gruntSaucelabs: json["grunt-saucelabs"],
        gruntContribConnect: json["grunt-contrib-connect"],
